{{
  (() => {
    const r = GetRoute.data;
    const s = GetRoute_Shortest.data;
    if (!r?.success) return "";
    const prefDist = (r.totalDistance / 1000).toFixed(1);
    const prefTime = r.estimatedTime.toFixed(0);
    let result = "\u{1F6E1}\uFE0F Safe Route: " + prefDist + " km | " + prefTime + " min";
    if (s?.success) {
      const shortDist = (s.totalDistance / 1000).toFixed(1);
      const shortTime = s.estimatedTime.toFixed(0);
      const extraDist = (prefDist - shortDist).toFixed(1);
      const extraTime = (prefTime - shortTime).toFixed(0);
      result += "\n\u26A1 Shortest: " + shortDist + " km | " + shortTime + " min";
      if (Number(extraDist) > 0) {
        result += "\n\u2139\uFE0F Your safe route adds ~" + extraDist + " km (" + extraTime + " min) for better accessibility & safety.";
      } else {
        result += "\n\u2705 Your safe route is also the shortest!";
      }
    }
    const prefs = Get_User_Preferences.data?.preferences;
    if (prefs) {
      const factors = [];
      if (prefs.wheelchairWeight > 0) factors.push("wheelchair access (" + prefs.wheelchairWeight + "/10)");
      if (prefs.crimeWeight > 0) factors.push("crime avoidance (" + prefs.crimeWeight + "/10)");
      if (prefs.lightingWeight > 0) factors.push("street lighting (" + prefs.lightingWeight + "/10)");
      if (prefs.constructionWeight > 0) factors.push("construction avoidance (" + prefs.constructionWeight + "/10)");
      if (prefs.maxDistanceToHospital > 0) factors.push("hospital proximity (<" + (prefs.maxDistanceToHospital/1000).toFixed(1) + " km)");
      if (factors.length > 0) {
        result += "\n\u{1F4CB} Factors: " + factors.join(", ");
      }
    }
    return result;
  })()
}}

