let map;
let routeLayer;
let poiLayer;
let heatLayer;
appsmith.onReady(() => {
  map = L.map('map').setView([43.65, -79.38], 13);

  L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
    maxZoom: 19,
    attribution: '\u00a9 OpenStreetMap contributors \u00a9 CARTO'
  }).addTo(map);

  routeLayer = L.layerGroup().addTo(map);
  poiLayer = L.layerGroup().addTo(map);
});
appsmith.onModelChange(model => {
  if (!map || !model.markers) return;

  routeLayer.clearLayers();
  poiLayer.clearLayers();

  const bounds = L.latLngBounds();
  const routeMarkers = model.markers.filter(m => m.type !== "poi");
  const poiMarkers = model.markers.filter(m => m.type === "poi");

  routeMarkers.forEach((marker, index) => {
    const latLng = [marker.lat, marker.long];
    bounds.extend(latLng);
    if (index === 0) {
      L.marker(latLng).addTo(routeLayer).bindPopup(marker.title);
    } else if (index === routeMarkers.length - 1) {
      L.marker(latLng).addTo(routeLayer).bindPopup(marker.title);
    } else {
      L.circleMarker(latLng, {
        radius: 6,
        fillColor: "#ff7800",
        color: "#000",
        weight: 1,
        opacity: 1,
        fillOpacity: 0.8
      }).addTo(routeLayer).bindPopup(marker.title);
    }
  });

  // Draw route polyline connecting waypoints
  if (routeMarkers.length > 2) {
    const routeCoords = routeMarkers.map(m => [m.lat, m.long]);
    L.polyline(routeCoords, {
      color: "#2563eb",
      weight: 4,
      opacity: 0.8
    }).addTo(routeLayer);
  }

  // Render POI markers with distinct styling
  poiMarkers.forEach(marker => {
    const latLng = [marker.lat, marker.long];
    bounds.extend(latLng);
    L.circleMarker(latLng, {
      radius: 8,
      fillColor: "#e11d48",
      color: "#fff",
      weight: 2,
      opacity: 1,
      fillOpacity: 0.9
    }).addTo(poiLayer).bindPopup(marker.title);
  });

  if (model.markers.length > 0) {
    map.fitBounds(bounds, { padding: [30, 30] });
  }

  // Handle heatmap data
  if (heatLayer) {
    map.removeLayer(heatLayer);
    heatLayer = null;
  }
  if (model.heatmapPoints && model.heatmapPoints.length > 0) {
    const heatData = model.heatmapPoints.map(p => [p[0], p[1], 0.5]);
    heatLayer = L.heatLayer(heatData, {
      radius: 20,
      blur: 15,
      maxZoom: 17,
      gradient: {0.2: 'blue', 0.4: 'lime', 0.6: 'yellow', 0.8: 'orange', 1.0: 'red'}
    }).addTo(map);
  }
});

