actionConfiguration.body:
async () => {
  if (!StartAddress.text?.trim() || !EndAddress.text?.trim()) {
    showAlert("Please enter both start and destination", "warning");
    return;
  }
  try {
    await GeocodeStart.run();
  } catch (e) {
    showAlert(GeocodeStart.data?.message || "Start address not found", "error");
    return;
  }
  try {
    await GeocodeEnd.run();
  } catch (e) {
    showAlert(GeocodeEnd.data?.message || "Destination address not found", "error");
    return;
  }
  try {
    const [prefResult, shortResult] = await Promise.allSettled([GetRoute.run(), GetRoute_Shortest.run()]);
    if (GetRoute.data?.success) {
      let msg = "Route found";
      if (GetRoute_Shortest.data?.success) {
        const prefDist = (GetRoute.data.totalDistance / 1000).toFixed(1);
        const shortDist = (GetRoute_Shortest.data.totalDistance / 1000).toFixed(1);
        const prefTime = GetRoute.data.estimatedTime.toFixed(0);
        const shortTime = GetRoute_Shortest.data.estimatedTime.toFixed(0);
        await storeValue("routeComparison", {
          preferred: {
            distance: prefDist,
            time: prefTime
          },
          shortest: {
            distance: shortDist,
            time: shortTime
          }
        });
        msg = "Safe route: " + prefDist + "km (" + prefTime + "min) vs Shortest: " + shortDist + "km (" + shortTime + "min)";
      }
      showAlert(msg, "success");
    } else {
      showAlert(GetRoute.data?.message || "No route found", "warning");
    }
  } catch (e) {
    showAlert(GetRoute.data?.message || "Failed to calculate route", "error");
  }
}

