export default {
	loadConversation: async () => {
  try {
    const currentUserId = Number(appsmith.store.userId);
    const selectedUserId = Number(appsmith.store.selectedUser?.userId);

    if (!selectedUserId) {
      await storeValue("selectedConversation", []);
      return;
    }

    const myInboxResponse = await api_getInbox.run();
    const selectedInboxResponse = await api_getSelectedInbox.run();

    const myInbox = myInboxResponse?.messages || [];
    const selectedInbox = selectedInboxResponse?.messages || [];

    const incoming = myInbox.filter(
      m => Number(m.senderId) === selectedUserId
    );

    const outgoing = selectedInbox.filter(
      m => Number(m.senderId) === currentUserId
    );

    const merged = [...incoming, ...outgoing].sort(
      (a, b) => new Date(a.timestamp) - new Date(b.timestamp)
    );

    await storeValue("selectedConversation", merged);
  } catch (error) {
    showAlert("Failed to load conversation", "error");
    console.log("Conversation load error:", error);
  }
}
}

