export default {
	getMarkers: () => {
		const defaultCenter = { lat: 43.65, long: -79.38, title: "Toronto" };

		const startLat = GeocodeStart.data?.lat;
		const startLng = GeocodeStart.data?.lng;
		const endLat = GeocodeEnd.data?.lat;
		const endLng = GeocodeEnd.data?.lng;

		const hasStartPoint =
					typeof startLat === "number" && typeof startLng === "number";

		const hasEndPoint =
					typeof endLat === "number" && typeof endLng === "number";

		const hasRoute =
					GetRoute.data?.success &&
					Array.isArray(GetRoute.data?.coordinates) &&
					GetRoute.data.coordinates.length > 0;

		let markers = [];

		if (hasRoute) {
			markers = GetRoute.data.coordinates.map((coordinate, index, coordinates) => ({
				lat: coordinate[0],
				long: coordinate[1],
				title:
				index === 0
				? "Start"
				: index === coordinates.length - 1
				? "End"
				: `Waypoint ${index}`,
				type: "route"
			}));
		} else if (hasStartPoint && hasEndPoint) {
			markers = [
				{ lat: startLat, long: startLng, title: "Start", type: "route" },
				{ lat: endLat, long: endLng, title: "End", type: "route" }
			];
		} else if (hasStartPoint) {
			markers = [{ lat: startLat, long: startLng, title: "Start", type: "route" }];
		} else if (hasEndPoint) {
			markers = [{ lat: endLat, long: endLng, title: "End", type: "route" }];
		} else {
			markers = [{ ...defaultCenter, type: "default" }];
		}

		// Add hospital POI markers if toggled on
		if (appsmith.store.showPOIs && typeof Get_Hospital_Services !== "undefined" && Array.isArray(Get_Hospital_Services?.data)) {
			const poiMarkers = Get_Hospital_Services.data.map(poi => ({
				lat: poi.latitude || poi.lat,
				long: poi.longitude || poi.lng,
				title: " " + (poi.name || "Health Service"),
				type: "poi"
			})).filter(m => m.lat && m.long);
			markers = [...markers, ...poiMarkers];
		}

		return markers;
	}
};

