  loginFlow: async () => {
    try {
      const response = await api_login.run();

      if (response) {
        await storeValue("isLoggedIn", true, false);
        await storeValue("userId", response.userId, false);
        await storeValue("displayName", response.displayName, false);
        await storeValue("preferences", response.preferences, false);

        showAlert("Welcome back, " + (response.displayName || "User") + "!", "success");
        navigateTo("Map and Navigation", {}, "SAME_WINDOW");
      }
    } catch (error) {
      const errorMessage =
        api_login.data?.message || "Invalid credentials. Please try again.";
      showAlert(errorMessage, "error");
    }
  },

  signupFlow: async () => {
  const pwd = inp_registerPassword.text || "";
  if (pwd.length < 8 || pwd.length > 100) {
    showAlert("Password must be between 8 and 100 characters", "error");
    return;
  }
  if (!inp_UserName.text?.trim()) {
    showAlert("Username is required", "error");
    return;
  }
  const usernameRegex = /^[a-zA-Z0-9_]{3,30}$/;
  if (!usernameRegex.test(inp_UserName.text.trim())) {
    showAlert("Username must be 3-30 characters (letters, numbers, underscores only)", "error");
    return;
  }
  try {
    const response = await api_signup.run();

    if (response?.success === false) {
      showAlert(response.message || "Signup failed", "error");
      return;
    }

    await storeValue("isLoggedIn", true);
    await storeValue("userId", response.userId);
    await storeValue("displayName", response.displayName);
    await storeValue("preferences", response.preferences);

    showAlert("Account created successfully!", "success");
    navigateTo("Map and Navigation", {}, "SAME_WINDOW");

  } catch (error) {
    const errMsg = api_signup.data?.message || error?.message || "Failed to create account";
    if (errMsg.toLowerCase().includes("username already taken") || errMsg.toLowerCase().includes("already exists")) {
      showAlert("This username is already taken. Please choose a different username.", "error");
    } else {
      showAlert(errMsg, "error");
    }
    console.log("Signup error:", error);
  }
},

  logout: async () => {
    await clearStore();
    navigateTo("Login and Sign Up", {}, "SAME_WINDOW");
  },

